function solve(nums) {
    // This problem is equivalent to finding the longest subsequence of nums
    // that is of the form [0, 1, 2, ..., k-1] for some k.
    // If we select a subsequence, its elements maintain their relative order.
    // If the selected subsequence is [n'_0, n'_1, ..., n'_{k-1}],
    // for it to have k fixed points, we must have n'_i = i for all i from 0 to k-1.
    // This means we are looking for the longest subsequence that equals [0, 1, 2, ..., k-1].

    // We can use a greedy approach. We want to match 0 first, then 1, then 2, and so on.

    let target = 0; // The value we are currently looking for (0, 1, 2, ...)
    let count = 0;  // The number of fixed points found so far (which is also the length of the sequence [0, 1, ..., target-1])

    for (let i = 0; i < nums.length; i++) {
        if (nums[i] === target) {
            // Found the next required element in the sequence [0, 1, 2, ...]
            count++;
            target++; // Look for the next element
        }
    }

    // 'count' is the length of the longest subsequence that matches [0, 1, ..., count-1],
    // which means we achieved 'count' fixed points.
    return count;
}

